@import url("https://fonts.googleapis.com/css2?family=Poppins:ital,wght@0,100;0,200;0,300;0,400;0,500;0,600;0,700;0,800;0,900&display=swap");
:root {
  --font-primary: "Poppins", sans-serif;
  --fw-regular: 400;
  --fw-medium: 500;
  --fw-semibold: 600;
  --color-text: #596d7b;
  --color-primary: #82DB35;
  --color-secondary: #204A83;
  --radius-sm: 4px;
  --spacing: 1rem;
  --logo-padding: 0.5rem;
  --grid-col-logo-width: 1fr;
  --grid-col-info-width: 1fr;
  --grid-col-savings-width: 1fr;
  --grid-col-actions-width: 1fr;
}

body {
  margin: 0;
  padding: 0;
  font-family: var(--font-primary);
}

.cta-offer {
  display: grid;
  grid-template-columns: var(--grid-col-logo-width) var(--grid-col-info-width) var(--grid-col-savings-width) var(--grid-col-actions-width);
  align-items: center;
  gap: var(--spacing);
  padding: var(--spacing);
  width: 95%;
  max-width: 1200px;
  margin: 0 auto;
  background: transparent;
}

.cta-offer__logo {
  justify-self: center;
  align-self: center;
  border-radius: var(--radius-sm);
  padding: var(--logo-padding);
  display: flex;
  align-items: center;
  justify-content: center;
  overflow: hidden;
}

.cta-offer__logo img {
  display: block;
  width: 100%;
  max-width: 180px;
  height: auto;
}

.cta-offer__info {
  display: flex;
  flex-direction: column;
  align-items: center;
  justify-content: center;
  text-align: center;
  height: 100%;
}

.cta-offer__title {
  font-size: 1.25rem;
  font-weight: var(--fw-semibold);
  color: #a6b2bb;
  margin: 0;
}

.cta-offer__price {
  font-size: 1rem;
  font-weight: var(--fw-medium);
  color: var(--color-text);
  margin-top: 0.5rem;
}

.cta-offer__savings {
  display: flex;
  align-items: center;
  justify-content: center;
  text-align: center;
  font-size: 1rem;
  font-weight: var(--fw-medium);
  color: var(--color-primary);
  height: 100%;
}

.cta-offer__actions {
  display: flex;
  flex-direction: column;
  align-items: center;
  justify-content: center;
  gap: 0.5rem;
  height: 100%;
}

.btn-cta {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  padding: 0.75em 1em;
  font-family: var(--font-primary);
  font-weight: var(--fw-semibold);
  font-size: 1rem;
  border: none;
  border-radius: var(--radius-sm);
  cursor: pointer;
  color: white;
  transition: background-color 0.2s ease;
  width: 100%;
  max-width: 220px;
}

.btn-cta:not(:last-child) {
  margin-bottom: var(--spacing, 0.5rem);
}

.btn-cta--primary {
  background-color: var(--color-primary);
}

.btn-cta--primary:hover {
  background-color: #9BE69E;
}

.btn-cta--secondary {
  background-color: var(--color-secondary);
}

.btn-cta--secondary:hover {
  background-color: #163F6B;
}

.btn-cta-disabled,
.btn-cta-disabled:hover {
  background-color: #cccccc;
  color: #666666;
  cursor: not-allowed;
  opacity: 0.6;
}

.btn-cta svg {
  width: 1em;
  height: 1em;
  margin-right: 0.5em;
}

@media screen and (max-width: 768px) {
  .cta-offer {
    display: flex;
    flex-direction: column;
    align-items: center;
    width: 100%;
  }
  .cta-offer__logo,
  .cta-offer__info,
  .cta-offer__savings,
  .cta-offer__actions {
    width: 100%;
    max-width: 400px;
    justify-content: center;
  }
  .cta-offer__actions {
    flex-direction: row;
    justify-content: center;
    gap: var(--spacing, 0.5rem);
  }
  .cta-offer__actions .btn-cta {
    flex: 1;
    width: auto;
    max-width: none;
  }
  .btn-cta:not(:last-child) {
    margin-bottom: 0;
  }
}

